<script lang="ts">
  import type { ChartDataPayload } from '@toaster/types';
  import { onMount } from 'svelte';

  import Scaffold from '../_common/Scaffold.svelte';

  import XYLayout from '../_common/Axes/XYLayout.svelte';

  import LineData from './LineData.svelte';
  import type { ToasterNonDataOptions } from '@pantry/types';
  import Legends from '../_common/Legends/Legends.svelte';
  import AnnotationLayer from '../_common/Annotations/AnnotationLayer.svelte';

  import {
    resetTextCalcCaches,
    getScales,
    makeSeriesDataLookup,
    mapChartData,
    DEFAULT_CHART_WIDTH,
    DEFAULT_OPTIONS,
    LEGEND_MARGIN,
    getScaffoldHeight,
  } from '@pantry/charts/utils';
  import SeriesTooltip from '../_common/Tooltip/SeriesTooltip.svelte';
  import {
    getSeriesDataLookup,
    getTooltipPosition,
    getAnnotationPosition,
    setSeriesDataLookup,
    setTooltipPosition,
    setAnnotationPosition,
    setAnnotationMode,
    getAnnotationMode,
  } from '../../utils/context.js';
  import { getChartHeightFromWidth } from '../utils/aspect.utils.js';
  import { getIsMobile } from '@toaster/utils';
  import type { SvgDimensionLayout } from '../_common/Annotations/annotation.utils.js';

  interface Props {
    chartData: ChartDataPayload<'v1'>;
    initialWidth?: number;
    options?: ToasterNonDataOptions;
  }

  let {
    chartData: chartDataProp,
    initialWidth = DEFAULT_CHART_WIDTH,
    options: optionsProp = {
      ...DEFAULT_OPTIONS,
    },
  }: Props = $props();

  // Merge options with defaults
  const options = $derived({ ...DEFAULT_OPTIONS, ...optionsProp });

  // Map chart data (add data to fields object)
  const chartData = $derived(mapChartData(chartDataProp));

  // State variables
  let width = $state(initialWidth);
  let footerHeight = $state(0);
  let headerHeight = $state(0);
  let legendHeight = $state(0);

  // Initialize context-wrapped stores
  setTooltipPosition();
  setAnnotationPosition();
  setSeriesDataLookup();
  setAnnotationMode();
  const tooltipPosition = getTooltipPosition();
  const annotationPosition = getAnnotationPosition();
  const seriesDataLookup = getSeriesDataLookup();
  const annotationMode = getAnnotationMode();

  // Derived values
  const height = $derived(getChartHeightFromWidth(width, chartData));
  const isMobile = $derived(getIsMobile(width));
  const scaffoldHeight = $derived(getScaffoldHeight(headerHeight, isMobile));
  const editAnnotationIsDisabled = $derived($annotationMode === 'DISABLED');
  const layerId = $derived(
    (options.isTerminalClient ? 'terminal' : 'web') +
      (isMobile ? 'Mobile' : 'Desktop'),
  );

  // Create scales
  const scales = $derived.by(() => {
    return chartData
      ? getScales({
          chartData,
          width,
          height,
          options,
          seriesDataLookup: $seriesDataLookup,
          scaffoldHeight,
          legendHeight,
          layerId,
        })
      : null;
  });

  const svgLayouts: SvgDimensionLayout = $derived({
    legends: legendHeight ? legendHeight + LEGEND_MARGIN : 0,
    content: [
      {
        legends: 0,
        subtitle: 0,
        width: scales?.primaryScale.scale.scale.range()[1] ?? 0,
        height,
        padding: {
          right: scales?.padding?.right ?? 0,
          left: scales?.padding?.left ?? 0,
          top: scales?.padding?.top ?? 0,
          bottom: scales?.padding?.bottom ?? 0,
        },
      },
    ],
  });

  // Update series data lookup
  $effect(() => {
    $seriesDataLookup = makeSeriesDataLookup(chartData);
  });

  // Handle annotation mode changes
  $effect(() => {
    if ($annotationMode === 'IDLE') {
      $tooltipPosition = null;
      $annotationPosition = null;
    }
  });

  // Handle font loading
  onMount(() => {
    // Fonts now loaded locally from app/public directory IN ADDITION TO style tag.
    // this prompts an update when those files are loaded for correct calculation of size
    document.fonts.ready.then(() => {
      resetTextCalcCaches();
      // Trigger recalculation by updating seriesDataLookup
      $seriesDataLookup = makeSeriesDataLookup(chartData);
    });
  });

  // Event handlers
  const handleChartHover = (e: MouseEvent) => {
    $tooltipPosition = { x: e.offsetX, y: e.offsetY };
    $annotationPosition = { x: e.offsetX, y: e.offsetY };
  };

  const handleChartLeave = () => {
    $tooltipPosition = null;
    $annotationPosition = null;
  };
</script>

{#key chartData}
  {#if scales}
    <div bind:clientWidth={width} class="toaster--chart-container">
      <!-- ts throwing error here bc of prop type specification in scaffold component-->
      <Scaffold
        {chartData}
        {options}
        enable={true}
        bind:headerHeight
        bind:footerHeight
      >
        <Legends {scales} {chartData} {options} {width} bind:legendHeight />
        <div style="position: relative">
          <svg
            style={`
          height: ${height}px;
          width: ${width}px;
        `}
            role="img"
            aria-label="Line chart"
            onmousemove={(e) => handleChartHover(e)}
            onmouseleave={(_) => handleChartLeave()}
          >
            <XYLayout {scales} {options} {chartData} {width} {height}>
              <LineData {scales} {chartData} {options} {width} {height} />
              <AnnotationLayer
                {scales}
                {chartData}
                {width}
                {options}
                {scaffoldHeight}
                {svgLayouts}
                type={chartData.type}
                {isMobile}
              />
            </XYLayout>
          </svg>
          {#if editAnnotationIsDisabled}
            <SeriesTooltip {scales} {chartData} {width} {height} {options} />
          {/if}
        </div>
      </Scaffold>
    </div>
  {/if}
{/key}

<style lang="postcss">
  .toaster--chart-container {
    letter-spacing: auto;
  }
</style>
